using Microsoft.Shared.Diagnostics;

namespace Microsoft.Agents.AI;

/// <summary>
/// Provides a builder for creating pipelines of <see cref="T:Microsoft.Agents.AI.AIAgent" />s.
/// </summary>
public sealed class AIAgentBuilder
{
	/// <summary>
	/// Provides an empty <see cref="T:System.IServiceProvider" /> implementation.
	/// </summary>
	private sealed class EmptyServiceProvider : IServiceProvider, IKeyedServiceProvider
	{
		/// <summary>Gets the singleton instance of <see cref="T:Microsoft.Agents.AI.AIAgentBuilder.EmptyServiceProvider" />.</summary>
		public static EmptyServiceProvider Instance { get; } = new EmptyServiceProvider();

		/// <inheritdoc />
		public object? GetService(Type serviceType)
		{
			return null;
		}

		/// <inheritdoc />
		public object? GetKeyedService(Type serviceType, object? serviceKey)
		{
			return null;
		}

		/// <inheritdoc />
		public object GetRequiredKeyedService(Type serviceType, object? serviceKey)
		{
			throw new InvalidOperationException($"No service for type '{serviceType}' has been registered.");
		}
	}

	private readonly Func<IServiceProvider, AIAgent> _innerAgentFactory;

	/// <summary>The registered agent factory instances.</summary>
	private List<Func<AIAgent, IServiceProvider, AIAgent>>? _agentFactories;

	/// <summary>Initializes a new instance of the <see cref="T:Microsoft.Agents.AI.AIAgentBuilder" /> class.</summary>
	/// <param name="innerAgent">The inner <see cref="T:Microsoft.Agents.AI.AIAgent" /> that represents the underlying backend.</param>
	/// <exception cref="T:System.ArgumentNullException"><paramref name="innerAgent" /> is <see langword="null" />.</exception>
	public AIAgentBuilder(AIAgent innerAgent)
	{
		Throw.IfNull<AIAgent>(innerAgent, "innerAgent");
		_innerAgentFactory = (IServiceProvider _) => innerAgent;
	}

	/// <summary>Initializes a new instance of the <see cref="T:Microsoft.Agents.AI.AIAgentBuilder" /> class.</summary>
	/// <param name="innerAgentFactory">A callback that produces the inner <see cref="T:Microsoft.Agents.AI.AIAgent" /> that represents the underlying backend.</param>
	/// <exception cref="T:System.ArgumentNullException"><paramref name="innerAgentFactory" /> is <see langword="null" />.</exception>
	public AIAgentBuilder(Func<IServiceProvider, AIAgent> innerAgentFactory)
	{
		_innerAgentFactory = Throw.IfNull(innerAgentFactory, "innerAgentFactory");
	}

	/// <summary>Builds an <see cref="T:Microsoft.Agents.AI.AIAgent" /> that represents the entire pipeline.</summary>
	/// <param name="services">
	/// The <see cref="T:System.IServiceProvider" /> that should provide services to the <see cref="T:Microsoft.Agents.AI.AIAgent" /> instances.
	/// If <see langword="null" />, an empty <see cref="T:System.IServiceProvider" /> will be used.
	/// </param>
	/// <returns>An instance of <see cref="T:Microsoft.Agents.AI.AIAgent" /> that represents the entire pipeline.</returns>
	/// <remarks>
	/// Calls to the resulting instance will pass through each of the pipeline stages in turn.
	/// </remarks>
	public AIAgent Build(IServiceProvider? services = null)
	{
		if (services == null)
		{
			services = EmptyServiceProvider.Instance;
		}
		AIAgent val = _innerAgentFactory(services);
