using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page-fetching tools for the research agent.
/// Uses the DuckDuckGo Instant Answer API (no API key required).
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query and returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var response = await _httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        var results = new List<string>();

        // Abstract (primary answer)
        var abstractText = response.GetPropertyOrDefault("AbstractText");
        var abstractUrl = response.GetPropertyOrDefault("AbstractURL");
        var abstractSource = response.GetPropertyOrDefault("AbstractSource");
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.Add($"[{abstractSource}] {abstractText}\nURL: {abstractUrl}");
        }

        // Related topics
        if (response.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
        {
            foreach (var topic in topics.EnumerateArray().Take(8))
            {
                var text = topic.GetPropertyOrDefault("Text");
                var firstUrl = topic.GetPropertyOrDefault("FirstURL");
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.Add($"- {text}\n  URL: {firstUrl}");
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : $"No results found for '{query}'. Try a different or broader query.";
    }

    [Description("Fetches the text content from a web page URL. Use this to read the full content of a page found via search.")]
    public async Task<string> FetchWebPage(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var response = await _httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);

            // Strip HTML tags and collapse whitespace for a readable text extraction
            var text = StripHtmlTags().Replace(html, " ");
            text = CollapseWhitespace().Replace(text, " ").Trim();

            const int maxLength = 4000;
            if (text.Length > maxLength)
            {
                text = string.Concat(text.AsSpan(0, maxLength), "... [truncated]");
            }

            return text;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch '{url}': {ex.Message}";
        }
    }

    public IEnumerable<AIFunction> CreateTools()
    {
        yield return AIFunctionFactory.Create(SearchWeb, name: "search_web", target: this);
        yield return AIFunctionFactory.Create(FetchWebPage, name: "fetch_web_page", target: this);
    }

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex StripHtmlTags();

    [GeneratedRegex(@"\s+")]
    private static partial Regex CollapseWhitespace();
}

internal static class JsonElementExtensions
{
    public static string GetPropertyOrDefault(this JsonElement element, string propertyName)
    {
        return element.TryGetProperty(propertyName, out var value)
            ? value.GetString() ?? string.Empty
            : string.Empty;
    }
}

using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking tools for the research agent to record and organize findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The note content — facts, quotes, or analysis to remember")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Returns all saved research notes. Use this to review what has been gathered so far before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, content) = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public IEnumerable<AIFunction> CreateTools()
    {
        yield return AIFunctionFactory.Create(SaveNote, name: "save_note", target: this);
        yield return AIFunctionFactory.Create(GetNotes, name: "get_notes", target: this);
    }
}

