using System.Net.Http.Headers;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.Add(new ProductInfoHeaderValue("ResearchAgent", "1.0"));

var webSearch = new WebSearchTool(httpClient);
var notes = new NoteTool();

var tools = webSearch.CreateTools()
    .Concat(notes.CreateTools())
    .ToList();

// --- Build the research agent using Microsoft Agent Framework ---
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research agent. Given a topic, you perform thorough research by:
        1. Searching the web for relevant information using the search_web tool.
        2. Fetching full page content when a search result looks promising using fetch_web_page.
        3. Saving key findings as notes using save_note (include source URLs).
        4. After gathering enough information (at least 3-5 notes), reviewing your notes
           with get_notes and producing a well-structured summary.

        Your final response must be a comprehensive summary that synthesizes all your notes,
        cites sources, and is organized with clear headings.
        """,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings.",
    tools: tools.ToList<AITool>());

// --- Prompt the user ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent             ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine("(The agent will search the web, take notes, and produce a summary.)");
Console.WriteLine(new string('─', 60));
Console.WriteLine();

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and produce a detailed summary: {topic}",
    session,
    new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    })))
{
    if (update.Role == ChatRole.Assistant && update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("Research complete.");

